use strict;
use warnings;

# Check if a filename is provided as an argument
if (@ARGV != 1) {
    die "Usage: $0 <filename>\n";
}

my $filename = $ARGV[0];

# Open the file for reading
open my $fh, '<', $filename or die "Could not open '$filename' for reading: $!";

# Initialize counters
my $total_lines = 0;
my $error_count = 0;

# Read the file line by line
while (my $line = <$fh>) {
    chomp $line; # Remove newline character
    $total_lines++;

    # Check if the line contains the word 'error' (case-insensitive)
    if ($line =~ /error/i) {
        $error_count++;
    }
}

# Close the file
